import { BedrockAgentRuntimeClient, InvokeAgentCommand } from '@aws-sdk/client-bedrock-agent-runtime';
import { Vex } from 'vex-sdk';

const bedrock = new BedrockAgentRuntimeClient({ region: 'us-east-1' });
const vex = new Vex({ apiKey: 'your-vex-key' });

async function invokeVerifiedAgent(sessionId: string, input: string) {
  const command = new InvokeAgentCommand({
    agentId: 'your-agent-id',
    agentAliasId: 'your-alias-id',
    sessionId,
    inputText: input
  });

  const response = await bedrock.send(command);
  const completion = await response.completion?.transformToByteStream();
  const chunks: Buffer[] = [];
  for await (const chunk of completion!) {
    chunks.push(Buffer.from(chunk.byteLength));
  }
  const agentOutput = Buffer.concat(chunks).toString();

  // Vex verification
  const result = await vex.verify({
    input,
    output: agentOutput,
    policy: 'fintech-bedrock-agent',
    context: { sessionId, regulation: 'BSA/AML' }
  });

  return result.valid ? result.output : `Blocked: ${result.issues[0].message}`;
}

